app.post('/api/entries/:id/teams', (req, res) => {
    const entry = entries[req.params.id];
    if (!entry) return res.status(404).json({ error: 'Entry not found' });
    const { teamName, leadName, totalCount, createdBy } = req.body;
    if (!teamName || !leadName) return res.status(400).json({ error: 'Team Name and Lead Name are required' });
    if (entry.teams.some(t => t.teamName.toLowerCase() === teamName.toLowerCase())) {
        return res.status(409).json({ error: `Team "${teamName}" already exists` });
    }
    const team = {
        id: uuidv4(), teamName, leadName, totalCount: Number(totalCount) || 0,
        createdDate: entry.date, createdBy: createdBy || 'UNKNOWN', lineItems: [],
    };
    entry.teams.push(team);
    saveData();
    res.status(201).json(team);
});

