app.post('/api/entries/:eid/teams/:tid/line-items', (req, res) => {
    const entry = entries[req.params.eid];
    if (!entry) return res.status(404).json({ error: 'Entry not found' });
    const team = entry.teams.find(t => t.id === req.params.tid);
    if (!team) return res.status(404).json({ error: 'Team not found' });
    const { name, careerLevel, allowanceCompoff } = req.body;
    if (!name) return res.status(400).json({ error: 'Name is required' });
    // Prevent duplicate names (case-insensitive)
    const duplicate = team.lineItems.find(li => li.name.toLowerCase() === name.trim().toLowerCase());
    if (duplicate) return res.status(409).json({ error: `"${name.trim()}" already exists in this team` });
    const item = { id: uuidv4(), name: name.trim(), careerLevel: careerLevel || '', allowanceCompoff: allowanceCompoff || 'Compoff', time: req.body.time || '' };
    team.lineItems.push(item);
    saveData();
    res.status(201).json(item);
});

app.post('/api/entries/:eid/teams/:tid/bulk-line-items', (req, res) => {
    const entry = entries[req.params.eid];
    if (!entry) return res.status(404).json({ error: 'Entry not found' });
    const team = entry.teams.find(t => t.id === req.params.tid);
    if (!team) return res.status(404).json({ error: 'Team not found' });
    const items = req.body.items;
    if (!Array.isArray(items)) return res.status(400).json({ error: 'items array required' });
    const added = [];
    const updated = [];
    items.forEach(({ name, careerLevel, allowanceCompoff }) => {
        if (!name || !name.trim()) return;
        const trimmedName = name.trim();
        const cl = careerLevel || '';
        const ac = allowanceCompoff || 'Compoff';
        // Check for existing item with same name (case-insensitive)
        const existingIdx = team.lineItems.findIndex(li =>
            li.name.toLowerCase() === trimmedName.toLowerCase());
        if (existingIdx !== -1) {
            // Overwrite existing item
            team.lineItems[existingIdx] = {
                ...team.lineItems[existingIdx],
                name: trimmedName,
                careerLevel: cl || team.lineItems[existingIdx].careerLevel,
                allowanceCompoff: ac,
            };
            updated.push(team.lineItems[existingIdx]);
        } else {
            const item = { id: uuidv4(), name: trimmedName, careerLevel: cl, allowanceCompoff: ac };
            team.lineItems.push(item);
            added.push(item);
        }
    });
    saveData();
    res.status(201).json({ added, updated, all: team.lineItems });
});

