app.post('/api/deleted-items/:id/recover', (req, res) => {
    const idx = deletedItems.findIndex(d => d.id === req.params.id);
    if (idx === -1) return res.status(404).json({ error: 'Deleted item not found' });
    const item = deletedItems[idx];
    let recovered = false;
    if (item.type === 'entry') {
        // Restore entry
        entries[item.data.id] = JSON.parse(JSON.stringify(item.data));
        recovered = true;
    } else if (item.type === 'team') {
        const entry = entries[item.parentInfo.entryId];
        if (entry) {
            entry.teams.push(JSON.parse(JSON.stringify(item.data)));
            recovered = true;
        } else {
            return res.status(400).json({ error: 'Parent entry no longer exists. Recover the entry first.' });
        }
    } else if (item.type === 'lineItem') {
        const entry = entries[item.parentInfo.entryId];
        if (!entry) return res.status(400).json({ error: 'Parent entry no longer exists.' });
        const team = entry.teams.find(t => t.id === item.parentInfo.teamId);
        if (!team) return res.status(400).json({ error: 'Parent team no longer exists. Recover the team first.' });
        team.lineItems.push(JSON.parse(JSON.stringify(item.data)));
        recovered = true;
    }
    if (recovered) {
        deletedItems.splice(idx, 1);
        saveData();
        return res.json({ success: true });
    }
    res.status(400).json({ error: 'Could not recover item' });
});

app.delete('/api/deleted-items/:id', (req, res) => {
    const idx = deletedItems.findIndex(d => d.id === req.params.id);
    if (idx === -1) return res.status(404).json({ error: 'Deleted item not found' });
    deletedItems.splice(idx, 1);
    saveData();
    res.json({ success: true });
});

